import React, { useState, useEffect, useRef } from 'react';

/* ─── GLOBAL STYLES ───────────────────────────────────────────────── */
const globalCss = `
  *, *::before, *::after { box-sizing: border-box; margin: 0; padding: 0; }
  html { scroll-behavior: smooth; }
  body {
    background: #0a0a0f;
    color: #e8e8f0;
    font-family: 'Inter', sans-serif;
    font-size: 16px;
    line-height: 1.6;
    -webkit-font-smoothing: antialiased;
  }
  a { color: inherit; text-decoration: none; }
  ::selection { background: rgba(124,58,237,0.4); }

  @keyframes fadeUp {
    from { opacity: 0; transform: translateY(24px); }
    to   { opacity: 1; transform: translateY(0); }
  }
  @keyframes blink {
    0%, 100% { opacity: 1; } 50% { opacity: 0; }
  }
  @keyframes pulse-ring {
    0%   { transform: scale(1); opacity: 0.6; }
    100% { transform: scale(1.8); opacity: 0; }
  }

  @media (prefers-reduced-motion: reduce) {
    *, *::before, *::after { animation: none !important; transition: none !important; }
  }
`;

/* ─── TOKENS ──────────────────────────────────────────────────────── */
const T = {
  violet:    '#7c3aed',
  violetLt:  '#a78bfa',
  violetDim: 'rgba(124,58,237,0.15)',
  bg:        '#0a0a0f',
  bgCard:    '#111118',
  bgCardHov: '#16161f',
  border:    'rgba(255,255,255,0.07)',
  borderHov: 'rgba(124,58,237,0.5)',
  textPri:   '#e8e8f0',
  textSec:   'rgba(232,232,240,0.55)',
  textMuted: 'rgba(232,232,240,0.3)',
  mono:      "'JetBrains Mono', monospace",
};

/* ─── TYPEWRITER HOOK ─────────────────────────────────────────────── */
function useTypewriter(words, speed = 80, pause = 1800) {
  const [display, setDisplay] = useState('');
  const [wordIdx, setWordIdx] = useState(0);
  const [charIdx, setCharIdx] = useState(0);
  const [deleting, setDeleting] = useState(false);

  useEffect(() => {
    const current = words[wordIdx];
    const delay = deleting ? speed / 2 : speed;

    const timer = setTimeout(() => {
      if (!deleting && charIdx < current.length) {
        setDisplay(current.slice(0, charIdx + 1));
        setCharIdx(c => c + 1);
      } else if (!deleting && charIdx === current.length) {
        setTimeout(() => setDeleting(true), pause);
      } else if (deleting && charIdx > 0) {
        setDisplay(current.slice(0, charIdx - 1));
        setCharIdx(c => c - 1);
      } else {
        setDeleting(false);
        setWordIdx(i => (i + 1) % words.length);
      }
    }, delay);

    return () => clearTimeout(timer);
  }, [charIdx, deleting, wordIdx, words, speed, pause]);

  return display;
}

/* ─── INTERSECTION OBSERVER HOOK ─────────────────────────────────── */
function useFadeIn(threshold = 0.15) {
  const ref = useRef(null);
  const [visible, setVisible] = useState(false);
  useEffect(() => {
    const el = ref.current;
    if (!el) return;
    const obs = new IntersectionObserver(
      ([entry]) => { if (entry.isIntersecting) { setVisible(true); obs.disconnect(); } },
      { threshold }
    );
    obs.observe(el);
    return () => obs.disconnect();
  }, [threshold]);
  return [ref, visible];
}

/* ─── NAV ─────────────────────────────────────────────────────────── */
function Nav({ active }) {
  const [scrolled, setScrolled] = useState(false);
  const [menuOpen, setMenuOpen] = useState(false);

  useEffect(() => {
    const onScroll = () => setScrolled(window.scrollY > 40);
    window.addEventListener('scroll', onScroll);
    return () => window.removeEventListener('scroll', onScroll);
  }, []);

  const links = ['About', 'Skills', 'Projects', 'Contact'];

  const navStyle = {
    position: 'fixed', top: 0, left: 0, right: 0, zIndex: 100,
    padding: '0 2rem',
    height: '60px',
    display: 'flex', alignItems: 'center', justifyContent: 'space-between',
    background: scrolled ? 'rgba(10,10,15,0.92)' : 'transparent',
    backdropFilter: scrolled ? 'blur(12px)' : 'none',
    borderBottom: scrolled ? `1px solid ${T.border}` : 'none',
    transition: 'background 0.3s, border-color 0.3s',
  };

  return (
    <nav style={navStyle}>
      <span style={{ fontFamily: T.mono, fontSize: 14, color: T.violet, fontWeight: 600, letterSpacing: '-0.5px' }}>
        SS<span style={{ color: T.textMuted }}>.iam</span>
      </span>
      <div style={{ display: 'flex', gap: '2rem' }}>
        {links.map(l => (
          <a
            key={l}
            href={`#${l.toLowerCase()}`}
            style={{
              fontSize: 13, fontWeight: 500,
              color: active === l.toLowerCase() ? T.violetLt : T.textSec,
              transition: 'color 0.2s',
              letterSpacing: '0.2px',
            }}
            onMouseEnter={e => e.target.style.color = T.violetLt}
            onMouseLeave={e => e.target.style.color = active === l.toLowerCase() ? T.violetLt : T.textSec}
          >
            {l}
          </a>
        ))}
      </div>
    </nav>
  );
}

/* ─── HERO ────────────────────────────────────────────────────────── */
function Hero() {
  const roles = ['IAM Engineer', 'SailPoint Developer', 'BeanShell Craftsman', 'Identity Architect'];
  const typed = useTypewriter(roles);

  return (
    <section id="about" style={{
      minHeight: '100vh',
      display: 'flex', alignItems: 'center',
      padding: '6rem 2rem 4rem',
      maxWidth: 900, margin: '0 auto',
    }}>
      <div style={{ animation: 'fadeUp 0.7s ease both' }}>
        {/* eyebrow */}
        <div style={{
          display: 'inline-flex', alignItems: 'center', gap: 8,
          marginBottom: '1.5rem',
          background: T.violetDim,
          border: `1px solid rgba(124,58,237,0.3)`,
          borderRadius: 99, padding: '5px 14px',
        }}>
          <span style={{
            width: 7, height: 7, borderRadius: '50%', background: '#22c55e',
            position: 'relative',
          }}>
            <span style={{
              position: 'absolute', inset: 0, borderRadius: '50%',
              background: '#22c55e',
              animation: 'pulse-ring 1.8s ease-out infinite',
            }} />
          </span>
          <span style={{ fontSize: 12, fontFamily: T.mono, color: T.violetLt, fontWeight: 600 }}>
            Open to new roles
          </span>
        </div>

        {/* headline */}
        <h1 style={{
          fontSize: 'clamp(36px, 6vw, 64px)',
          fontWeight: 600,
          lineHeight: 1.1,
          letterSpacing: '-1.5px',
          marginBottom: '1rem',
          color: T.textPri,
        }}>
          Sai Srinath<br />
          <span style={{ color: T.violet }}>Enterprise</span>
        </h1>

        {/* typewriter */}
        <div style={{
          fontFamily: T.mono, fontSize: 'clamp(18px, 3vw, 26px)',
          color: T.violetLt, marginBottom: '1.5rem',
          minHeight: '2em',
        }}>
          {typed}
          <span style={{ animation: 'blink 1s step-end infinite', borderRight: `2px solid ${T.violetLt}`, marginLeft: 2 }} />
        </div>

        {/* bio */}
        <p style={{
          fontSize: 16, color: T.textSec, maxWidth: 520,
          lineHeight: 1.8, marginBottom: '2rem',
        }}>
          2 years building identity governance automation at scale — SailPoint IIQ workflows,
          JML lifecycle rules, and production integrations across GCP/Azure infrastructure.
          Based in Hyderabad, India.
        </p>

        {/* CTAs */}
        <div style={{ display: 'flex', gap: 12, flexWrap: 'wrap' }}>
          <a href="#projects" style={btnPrimary}>View Projects</a>
          <a href="#contact" style={btnOutline}>Get in touch</a>
